#!/usr/bin/env python3
"""Patch closeout_pipeline_run.py to support multi-arbitrage backlog export.

This is a temporary deterministic patcher.

Intent:
- keep STAGE_02 contract-compatible discovery of work/02_arbitrage/arbitrage*.md;
- preserve explicit single-file --arbitrage-path support;
- support directory --arbitrage-path by reading all arbitrage*.md inside it;
- export candidates from every discovered arbitrage report;
- keep export idempotent;
- annotate newly exported entries with source_arbitrage_path.
"""

from pathlib import Path

TARGET = Path("docs/patcher/shared/closeout_pipeline_run.py")


def replace_once(text: str, old: str, new: str) -> str:
    if old not in text:
        raise SystemExit(f"Expected block not found:\n{old[:500]}")
    return text.replace(old, new, 1)


def main() -> int:
    text = TARGET.read_text(encoding="utf-8")

    old_signature = '''def normalize_candidate_entry(\n    candidate: Dict[str, Any],\n    run_id: str,\n    fallback_scope_key: str,\n    current_stage: str,\n) -> Dict[str, Any]:\n    candidate_id = str(candidate.get("candidate_id") or "CANDIDATE").strip()\n    entry_id = build_entry_id(run_id, candidate_id)\n    return {\n        "entry_id": entry_id,\n        "type": str(candidate.get("backlog_entry_type") or "scope_gap"),\n        "status": "open",\n        "source_run_id": run_id,\n        "source_stage": current_stage,\n        "scope_key": fallback_scope_key,\n        "related_scope_keys": normalize_scope_keys(candidate.get("related_scope_keys"), fallback_scope_key),\n        "candidate_id": candidate_id,\n        "source_finding_id": str(candidate.get("source_finding_id") or "unknown"),\n        "title": str(candidate.get("title") or candidate_id),\n        "description": str(candidate.get("rationale") or candidate.get("title") or candidate_id),\n        "recommended_action": str(candidate.get("recommended_stage00_action") or "review_at_stage_00"),\n        "candidate_status": str(candidate.get("candidate_status") or "candidate_open"),\n        "recorded_at": utc_now_iso(),\n    }\n'''

    new_signature = '''def normalize_candidate_entry(\n    candidate: Dict[str, Any],\n    run_id: str,\n    fallback_scope_key: str,\n    current_stage: str,\n    source_arbitrage_path: Optional[Path] = None,\n) -> Dict[str, Any]:\n    candidate_id = str(candidate.get("candidate_id") or "CANDIDATE").strip()\n    entry_id = build_entry_id(run_id, candidate_id)\n    entry = {\n        "entry_id": entry_id,\n        "type": str(candidate.get("backlog_entry_type") or "scope_gap"),\n        "status": "open",\n        "source_run_id": run_id,\n        "source_stage": current_stage,\n        "scope_key": fallback_scope_key,\n        "related_scope_keys": normalize_scope_keys(candidate.get("related_scope_keys"), fallback_scope_key),\n        "candidate_id": candidate_id,\n        "source_finding_id": str(candidate.get("source_finding_id") or "unknown"),\n        "title": str(candidate.get("title") or candidate_id),\n        "description": str(candidate.get("rationale") or candidate.get("title") or candidate_id),\n        "recommended_action": str(candidate.get("recommended_stage00_action") or "review_at_stage_00"),\n        "candidate_status": str(candidate.get("candidate_status") or "candidate_open"),\n        "recorded_at": utc_now_iso(),\n    }\n    if source_arbitrage_path is not None:\n        entry["source_arbitrage_path"] = repo_path(source_arbitrage_path)\n    return entry\n'''

    text = replace_once(text, old_signature, new_signature)

    old_export = '''def export_backlog_entries(\n    run_id: str,\n    scope_key: str,\n    arbitrage_path: Path,\n    backlog_path: Path,\n    current_stage: str,\n) -> List[Dict[str, Any]]:\n    """Export governance backlog entries from arbitrage report.\n\n    Preferred mode: extract a structured YAML fenced block rooted at\n    governance_backlog_candidates.\n    Legacy fallback: extract Cxx notes and infer entry types heuristically.\n\n    Skips entries whose entry_id already exists (idempotent).\n    Returns the list of newly added entries.\n    """\n    structured_candidates = extract_structured_backlog_candidates(arbitrage_path)\n    legacy_notes = extract_backlog_notes_from_arbitrage(arbitrage_path) if not structured_candidates else []\n    if not structured_candidates and not legacy_notes:\n        return []\n\n    doc = load_governance_backlog(backlog_path)\n    entries: List[Dict[str, Any]] = doc["governance_backlog"]["entries"]\n    existing_ids = {e.get("entry_id") for e in entries}\n\n    added: List[Dict[str, Any]] = []\n\n    if structured_candidates:\n        for candidate in structured_candidates:\n            entry = normalize_candidate_entry(\n                candidate=candidate,\n                run_id=run_id,\n                fallback_scope_key=scope_key,\n                current_stage=current_stage,\n            )\n            if entry["entry_id"] in existing_ids:\n                continue\n            entries.append(entry)\n            added.append(entry)\n    else:\n        for note in legacy_notes:\n            entry_id = build_entry_id(run_id, note["note_id"])\n            if entry_id in existing_ids:\n                continue\n            entry: Dict[str, Any] = {\n                "entry_id": entry_id,\n                "type": infer_entry_type(note["description"]),\n                "status": "open",\n                "source_run_id": run_id,\n                "source_stage": current_stage,\n                "scope_key": scope_key,\n                "note_ref": note["note_id"],\n                "description": note["description"],\n                "recommended_action": "review_at_stage_00",\n                "recorded_at": utc_now_iso(),\n            }\n            entries.append(entry)\n            added.append(entry)\n\n    if added:\n        save_governance_backlog(backlog_path, doc)\n\n    return added\n'''

    new_export = '''def resolve_arbitrage_paths(arbitrage_path: Optional[Path], work_root: Path) -> List[Path]:\n    """Resolve arbitration reports using the STAGE_02 contract.\n\n    Rules:\n    - explicit file path: use that file only;\n    - explicit directory path: read every arbitrage*.md in that directory;\n    - absent path: read every <work_root>/02_arbitrage/arbitrage*.md;\n    - deterministic lexical ordering;\n    - no broad *.md scan, because unrelated notes may exist in the directory.\n    """\n    if arbitrage_path is not None:\n        if arbitrage_path.is_file():\n            return [arbitrage_path]\n        if arbitrage_path.is_dir():\n            return sorted(arbitrage_path.glob("arbitrage*.md"))\n        return []\n\n    default_dir = work_root / "02_arbitrage"\n    if default_dir.is_dir():\n        return sorted(default_dir.glob("arbitrage*.md"))\n\n    # Legacy fallback for older pipeline-level layouts.\n    legacy_file = work_root / "arbitrage.md"\n    if legacy_file.is_file():\n        return [legacy_file]\n\n    return []\n\n\ndef export_backlog_entries(\n    run_id: str,\n    scope_key: str,\n    arbitrage_path: Path,\n    backlog_path: Path,\n    current_stage: str,\n) -> List[Dict[str, Any]]:\n    """Export governance backlog entries from a single arbitrage report.\n\n    Preferred mode: extract a structured YAML fenced block rooted at\n    governance_backlog_candidates.\n    Legacy fallback: extract Cxx notes and infer entry types heuristically.\n\n    Skips entries whose entry_id already exists (idempotent).\n    Returns the list of newly added entries.\n    """\n    structured_candidates = extract_structured_backlog_candidates(arbitrage_path)\n    legacy_notes = extract_backlog_notes_from_arbitrage(arbitrage_path) if not structured_candidates else []\n    if not structured_candidates and not legacy_notes:\n        return []\n\n    doc = load_governance_backlog(backlog_path)\n    entries: List[Dict[str, Any]] = doc["governance_backlog"]["entries"]\n    existing_ids = {e.get("entry_id") for e in entries}\n\n    added: List[Dict[str, Any]] = []\n\n    if structured_candidates:\n        for candidate in structured_candidates:\n            entry = normalize_candidate_entry(\n                candidate=candidate,\n                run_id=run_id,\n                fallback_scope_key=scope_key,\n                current_stage=current_stage,\n                source_arbitrage_path=arbitrage_path,\n            )\n            if entry["entry_id"] in existing_ids:\n                continue\n            entries.append(entry)\n            existing_ids.add(entry["entry_id"])\n            added.append(entry)\n    else:\n        for note in legacy_notes:\n            entry_id = build_entry_id(run_id, note["note_id"])\n            if entry_id in existing_ids:\n                continue\n            entry: Dict[str, Any] = {\n                "entry_id": entry_id,\n                "type": infer_entry_type(note["description"]),\n                "status": "open",\n                "source_run_id": run_id,\n                "source_stage": current_stage,\n                "scope_key": scope_key,\n                "source_arbitrage_path": repo_path(arbitrage_path),\n                "note_ref": note["note_id"],\n                "description": note["description"],\n                "recommended_action": "review_at_stage_00",\n                "recorded_at": utc_now_iso(),\n            }\n            entries.append(entry)\n            existing_ids.add(entry_id)\n            added.append(entry)\n\n    if added:\n        save_governance_backlog(backlog_path, doc)\n\n    return added\n\n\ndef export_backlog_entries_from_paths(\n    run_id: str,\n    scope_key: str,\n    arbitrage_paths: List[Path],\n    backlog_path: Path,\n    current_stage: str,\n) -> List[Dict[str, Any]]:\n    added: List[Dict[str, Any]] = []\n    for path in arbitrage_paths:\n        added.extend(\n            export_backlog_entries(\n                run_id=run_id,\n                scope_key=scope_key,\n                arbitrage_path=path,\n                backlog_path=backlog_path,\n                current_stage=current_stage,\n            )\n        )\n    return added\n'''

    text = replace_once(text, old_export, new_export)

    old_help = '''    parser.add_argument(\n        "--arbitrage-path",\n        default=None,\n        help="Path to arbitrage report (default: <work-root>/arbitrage.md)",\n    )\n'''
    new_help = '''    parser.add_argument(\n        "--arbitrage-path",\n        default=None,\n        help=(\n            "Path to an arbitrage report file or to a directory containing arbitrage*.md. "\n            "Default: <work-root>/02_arbitrage/arbitrage*.md, with legacy fallback to <work-root>/arbitrage.md."\n        ),\n    )\n'''
    text = replace_once(text, old_help, new_help)

    old_main = '''        # --export-backlog-entries : extract entries from arbitrage report\n        if args.export_backlog_entries:\n            arbitrage_path = Path(\n                args.arbitrage_path\n                if args.arbitrage_path\n                else str(work_root / "arbitrage.md")\n            )\n            backlog_path = Path(args.backlog_path)\n            added = export_backlog_entries(\n                run_id=run_id_for_backlog,\n                scope_key=scope_key_for_backlog,\n                arbitrage_path=arbitrage_path,\n                backlog_path=backlog_path,\n                current_stage=args.current_stage,\n            )\n            backlog_entries_exported = len(added)\n            if added:\n                print(f"[backlog] {backlog_entries_exported} entrée(s) exportée(s) vers {args.backlog_path}:")\n                for e in added:\n                    title = e.get("title") or e.get("description") or e.get("entry_id")\n                    print(f"  + {e['entry_id']} [{e['type']}] — {str(title)[:80]}")\n            else:\n                print("[backlog] Aucune nouvelle entrée à exporter (aucun candidat structuré, aucune note legacy, ou déjà présentes).")\n'''
    new_main = '''        # --export-backlog-entries : extract entries from one or more arbitrage reports\n        if args.export_backlog_entries:\n            explicit_arbitrage_path = Path(args.arbitrage_path) if args.arbitrage_path else None\n            arbitrage_paths = resolve_arbitrage_paths(explicit_arbitrage_path, work_root)\n            backlog_path = Path(args.backlog_path)\n            added = export_backlog_entries_from_paths(\n                run_id=run_id_for_backlog,\n                scope_key=scope_key_for_backlog,\n                arbitrage_paths=arbitrage_paths,\n                backlog_path=backlog_path,\n                current_stage=args.current_stage,\n            )\n            backlog_entries_exported = len(added)\n            print(f"[backlog] {len(arbitrage_paths)} fichier(s) d'arbitrage résolu(s).")\n            for path in arbitrage_paths:\n                print(f"  - {repo_path(path)}")\n            if added:\n                print(f"[backlog] {backlog_entries_exported} entrée(s) exportée(s) vers {args.backlog_path}:")\n                for e in added:\n                    title = e.get("title") or e.get("description") or e.get("entry_id")\n                    source = e.get("source_arbitrage_path", "unknown_source")\n                    print(f"  + {e['entry_id']} [{e['type']}] — {str(title)[:80]} ({source})")\n            else:\n                print("[backlog] Aucune nouvelle entrée à exporter (aucun candidat structuré, aucune note legacy, ou déjà présentes).")\n'''
    text = replace_once(text, old_main, new_main)

    TARGET.write_text(text, encoding="utf-8")
    print(f"Patched {TARGET}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
